configurationRead.query:
#graphql
  query GiftCardCreditLimitConfiguration {
    giftCardConfiguration {
      issueLimit { amount currencyCode }
      purchaseLimit { amount currencyCode }
    }
  }

setupCreate.query:
#graphql
  mutation GiftCardCreditLimitSetup($input: GiftCardCreateInput!) {
    giftCardCreate(input: $input) {
      giftCard {
        id
        initialValue { amount currencyCode }
        balance { amount currencyCode }
      }
      userErrors {
        field
        code
        message
      }
    }
  }

creditLimitExceeded.query:
#graphql
  mutation GiftCardCreditLimitExceeded($id: ID!, $input: GiftCardCreditInput!) {
    overLimitCredit: giftCardCredit(id: $id, creditInput: $input) {
      giftCardCreditTransaction {
        __typename
        amount { amount currencyCode }
      }
      userErrors {
        field
        code
        message
      }
    }
  }

readAfterRejectedCredit.query:
#graphql
  query GiftCardReadAfterRejectedCredit($id: ID!) {
    giftCard(id: $id) {
      id
      balance { amount currencyCode }
      transactions(first: 10) {
        nodes {
          __typename
          amount { amount currencyCode }
        }
      }
    }
  }

debitAfterRejectedCredit.query:
#graphql
  mutation GiftCardDebitAfterRejectedCredit($id: ID!, $input: GiftCardDebitInput!) {
    debitAfterRejectedCredit: giftCardDebit(id: $id, debitInput: $input) {
      giftCardDebitTransaction {
        __typename
        amount { amount currencyCode }
      }
      userErrors {
        field
        code
        message
      }
    }
  }

cleanup.query:
#graphql
      mutation GiftCardCreditLimitCleanup($id: ID!) {
        giftCardDeactivate(id: $id) {
          giftCard {
            id
            enabled
            deactivatedAt
          }
          userErrors {
            field
            code
            message
          }
        }
      }

upstreamCalls.query:
#graphql
    query GiftCardHydrate($id: ID!) {
      giftCard(id: $id) {
        id
        lastCharacters
        maskedCode
        enabled
        deactivatedAt
        expiresOn
        note
        templateSuffix
        createdAt
        updatedAt
        initialValue { amount currencyCode }
        balance { amount currencyCode }
        customer {
          id
          email
          defaultEmailAddress { emailAddress }
          defaultPhoneNumber { phoneNumber }
        }
        recipientAttributes {
          message
          preferredName
          sendNotificationAt
          recipient {
            id
            email
            defaultEmailAddress { emailAddress }
            defaultPhoneNumber { phoneNumber }
          }
        }
        transactions(first: 250) {
          nodes {
            __typename
            id
            note
            processedAt
            amount { amount currencyCode }
          }
        }
      }
      giftCardConfiguration {
        issueLimit { amount currencyCode }
        purchaseLimit { amount currencyCode }
      }
    }
